import { useState } from 'react';

export function Counter() {
  const [value, setValue] = useState(0);
  return (
    <div>
      <button onClick={() => setValue((v) => v - 1)}>-</button>
      <span>{value}</span>
      <button onClick={() => setValue((v) => v + 1)}>+</button>
    </div>
  );
}

